def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            for a in range(7, 1, -1):
                for b in range(1, a + 5):
                    term1 = ((ratio - a) ** 6) / (a * b * 0.85 + 1.2)
                    term2 = np.sin(ratio * b / (a + 0.8)) * np.exp(-(ratio - a))
                    priority += term1 * term2
            exp_comp = np.exp(ratio - 7)
            trig_comp = np.cos(ratio * 1.3)
            priority += (exp_comp ** 1.6) * (trig_comp ** 2)
        elif 4 < ratio <= 7:
            for x in range(1, int(np.ceil(ratio)) + 4):
                for y in range(1, x + 4):
                    inner_term = ((ratio - x) ** 4) * np.cos(ratio * x) / (y + 0.6)
                    priority += np.tanh(inner_term) * 1.3
            priority += np.log(ratio) * 11 - np.tanh(ratio - 4) * 2.5
            if bin_cap < item * 0.95:
                priority += np.sqrt(item / (bin_cap + 0.7)) * 3.7
        elif 2 <= ratio <= 4:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 2) ** r) / (r * 1.5) * np.sin(r * ratio * 0.9)
            priority = (s * np.sin(8 * ratio)) - np.log(ratio + 0.1) * 7 + np.tanh(3.5 * (4 - ratio)) * 2
            for u in range(1, 6):
                priority += np.cos(u * ratio * i) * ((ratio - 1.9) ** u) / (u + 1)
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 12):
                base = (2 - ratio) ** n
                s += base / (n ** 2 + 1) + np.sin(n * ratio * 3) * base / (n + 0.5)
            if bin_cap < item * 1.05:
                penalty = np.log1p(item / (bin_cap + 1)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i * 1.2) * ((ratio - 1) ** m) / (m ** 0.8)
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 20):
                s += ((1 - ratio) ** n) / (n * 3.5) * np.cos(n * item * 1.5)
            priority = s
            if (i * int(item * 1.7)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.5) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 18):
                s += ((0.5 - ratio) ** k) / (k * 2.5) * np.cos(k * ratio * 3)
            priority = s + 1 / (bin_cap + 4)
            if int(item * 1.5) % 5 == 0:
                priority *= 3
            else:
                priority /= 3.5
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.4)
        else:
            s = 0
            for t in range(1, 14):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.9) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.8
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 8) * np.cos(item * u * 0.9)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6
            for v in range(1, 5):
                priority += np.sin(v * ratio * i * 1.1) * ((ratio - 0.5) ** v) / (v + 1)
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5.5
            for w in range(2, 6):
                priority -= np.cos(w * ratio * (i + 1)) * 0.4
        for idx in range(1, 5):
            if (i + idx * 2) % 4 == 0:
                priority += np.sin(ratio * (i + idx)) * 0.35
            else:
                priority -= np.cos(ratio * (i + idx)) * 0.35
        if i % 2 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
